int main_test() {
    int size;
    std::cin >> size;

    if (size <= 0) {
        std::cout << "Array size must be positive." << std::endl;
        return 1;
    }

    int* arr = new int[size];

    for (int i = 0; i < size; ++i) {
        arr[i] = i;
    }

    std::cout << "Array elements: ";
    for (int i = 0; i < size; ++i) {
        std::cout << arr[i] << " ";
    }
    std::cout << std::endl;

    // The semantic error (memory leak) is the absence of delete[] arr;

    return 0;
}

int main() {
    // For semantic errors like memory leaks, the program's output might be correct,
    // but underlying resource management is flawed. Tools like Valgrind would detect this.
    return main_test();
}
